<template><div class="page container"><h1>收银台</h1><div class="soft-card p-6"><p>订单号：{{orderNo}} 金额：¥168.00</p><div class="grid md:grid-cols-5 gap-3"><n-button v-for="p in providers" :key="p" @click="pay(p)">{{p}}</n-button></div><pre v-if="result">{{result}}</pre></div></div></template><script setup lang="ts">import{ref}from'vue';import{NButton,useMessage}from'naive-ui';import{createPayment}from'../api/modules';const providers=['WECHAT_PAY','ALIPAY','STRIPE','CRYPTO','MOCK'];const orderNo='QG'+Date.now();const result=ref<any>();const msg=useMessage();async function pay(provider:string){result.value=(await createPayment({orderNo,provider,amount:168,subject:'企鹅莓果慕斯'}) as any).data;msg.success('支付单已创建')}</script>
